/**
 * Tool Usage Observer — Phase 1: JSONL Collection
 * 
 * Single convergence point for tool completion observations from both
 * ACP (Tier A: sequential, completion-order) and DirectProvider
 * (Tier B: rich, exec-order) paths.
 * 
 * Design: fail-silent, size-capped, redacted args, output truncation.
 * Phase 2: analyzer reads observations.jsonl to propose SKILL.
 */

import { appendFileSync, existsSync, mkdirSync, statSync } from "fs";
import { dirname, join } from "path";
import { config } from "./config.js";

// ─── Types ─────────────────────────────────────────────────────────────────

export type ObservationSource = "acp" | "direct";
export type PrecedingToolsSemantics = "exec-order" | "completion-order-approx";

/**
 * Rich observation: DirectProvider path only, per-tool detail.
 * 
 * precedingToolsSemantics="exec-order": precedingTools reflects actual
 * execution order from loop-local accumulation.
 */
export interface RichObservation {
  ts: string;
  source: "direct";
  sessionId: string;
  toolName: string;
  args: Record<string, unknown>;
  output: string;
  isError: boolean;
  precedingTools: string[];
  precedingToolsSemantics: "exec-order";
}

/**
 * Sequential observation: ACP path only, turn-level summary.
 * 
 * precedingToolsSemantics="completion-order-approx": precedingTools reflects
 * tool_call_update arrival order (parallel tools complete out-of-order),
 * NOT invocation order. Phase 2 analyzer must not treat as causal.
 */
export interface SequentialObservation {
  ts: string;
  source: "acp";
  sessionId: string;
  toolSequence: string[];
  precedingToolsSemantics: "completion-order-approx";
}

export type ToolObservation = RichObservation | SequentialObservation;

// ─── Config ────────────────────────────────────────────────────────────────

const OBSERVATIONS_PATH = join(config.memoryDir, "observations.jsonl");
const MAX_SIZE_BYTES = 32 * 1024 * 1024; // 32MB cap (BC-5)
const OUTPUT_TRUNCATE = 1000; // BC-5: prevent bloat from large tool outputs

// Args keys that should be redacted (BC-6: blacklist, known-leaky)
const REDACT_KEYS = new Set([
  "password",
  "token",
  "apiKey",
  "api_key",
  "secret",
  "auth",
  "authorization",
]);

// ─── Core Functions ────────────────────────────────────────────────────────

/**
 * Write a rich observation (Tier B: DirectProvider path).
 * 
 * Called from tool-loop.ts executeToolCalls try AND catch branches.
 * Fail-silent: never throws, logs errors to console only.
 */
export function writeRichObservation(
  sessionId: string,
  toolName: string,
  args: Record<string, unknown>,
  output: string,
  isError: boolean,
  precedingTools: string[]
): void {
  try {
    if (!shouldWrite()) return;

    const obs: RichObservation = {
      ts: new Date().toISOString(),
      source: "direct",
      sessionId,
      toolName,
      args: redactArgs(args),
      output: output.slice(0, OUTPUT_TRUNCATE),
      isError,
      precedingTools: [...precedingTools], // defensive copy
      precedingToolsSemantics: "exec-order",
    };

    writeObservation(obs);
  } catch (err) {
    // BC-5: fail-silent, log only
    console.error("[tool-observer] Failed to write rich observation:", err);
  }
}

/**
 * Write a sequential observation (Tier A: ACP path).
 * 
 * Called from sessionManager.ts resetTurn when activeProvider === "acp".
 * Fail-silent: never throws, logs errors to console only.
 */
export function writeSequentialObservation(
  sessionId: string,
  toolSequence: string[]
): void {
  try {
    if (!shouldWrite()) return;
    if (toolSequence.length === 0) return; // empty turn, skip

    const obs: SequentialObservation = {
      ts: new Date().toISOString(),
      source: "acp",
      sessionId,
      toolSequence: [...toolSequence], // defensive copy
      precedingToolsSemantics: "completion-order-approx",
    };

    writeObservation(obs);
  } catch (err) {
    // BC-5: fail-silent, log only
    console.error("[tool-observer] Failed to write sequential observation:", err);
  }
}

// ─── Internal Helpers ──────────────────────────────────────────────────────

function shouldWrite(): boolean {
  try {
    if (!existsSync(OBSERVATIONS_PATH)) return true;
    const stat = statSync(OBSERVATIONS_PATH);
    return stat.size < MAX_SIZE_BYTES;
  } catch {
    return true; // can't stat, assume ok to write
  }
}

function writeObservation(obs: ToolObservation): void {
  const dir = dirname(OBSERVATIONS_PATH);
  if (!existsSync(dir)) {
    mkdirSync(dir, { recursive: true });
  }

  appendFileSync(OBSERVATIONS_PATH, JSON.stringify(obs) + "\n", "utf-8");
}

/**
 * BC-6: Redact known-sensitive keys from args.
 * 
 * Known-leaky: only handles top-level keys, not nested objects.
 * Acceptable for Phase 1 (local memoryDir trust domain).
 */
function redactArgs(args: Record<string, unknown>): Record<string, unknown> {
  const redacted: Record<string, unknown> = {};
  for (const [key, val] of Object.entries(args)) {
    redacted[key] = REDACT_KEYS.has(key) ? "<redacted>" : val;
  }
  return redacted;
}
