export async function runToolLoop(
  adapter: LlmAdapter,
  pool: McpConnectionPool,
  messages: ChatMessage[],
  tools: ToolDefinition[],
  options: ToolLoopOptions = {}
): Promise<{ stopReason: string; usage?: Record<string, unknown> }> {
  const {
    maxIterations = 25,
    onText,
    onThinking,
    onToolStart,
    onToolEnd,
    contextWindow,
    sessionId, // ADD: new parameter for observation context
  } = options;

  // ADD: loop-local precedingTools accumulator (BC-1a: exec-order)
  const recentToolNames: string[] = [];

  let iteration = 0;
  while (iteration < maxIterations) {
    iteration++;

    const resp = await adapter.createMessage(messages, tools);

    // ... existing thinking/text handling ...

    if (resp.stopReason === "end_turn" || !resp.toolCalls?.length) {
      return { stopReason: resp.stopReason, usage: resp.usage };
    }

    // Tool calls
    const results = await executeToolCalls(
      resp.toolCalls,
      pool,
      onToolStart,
      onToolEnd,
      sessionId, // ADD: pass sessionId for observations
      recentToolNames // ADD: pass loop-local accumulator
    );

    // ... existing context-window handling ...
  }

  return { stopReason: "max_iterations", usage: undefined };
}

async function executeToolCalls(
  toolCalls: ToolCall[],
  pool: McpConnectionPool,
  onToolStart?: (name: string, input: unknown) => void,
  onToolEnd?: (name: string, output: string, isError: boolean) => void,
  sessionId?: string, // ADD: for observation context
  recentToolNames?: string[] // ADD: loop-local accumulator
): Promise<ToolResult[]> {
  return Promise.all(
    toolCalls.map(async (tc) => {
      const name = tc.name;
      let args = tc.input as Record<string, unknown>;

      onToolStart?.(name, args);

      // BC-7: snapshot args BEFORE RTK rewrite (F5 fix)
      const origArgs = { ...args };

      // RTK rewrite (existing logic)
      if (RTK_ENABLED && name === "shell") {
        args.command = applyRtkPrefix(args.command as string);
      }

      try {
        const output = await pool.callTool(name, args);
        const outStr = formatToolOutput(output);

        // ADD: write rich observation (BC-1: success branch)
        if (sessionId && recentToolNames) {
          writeRichObservation(
            sessionId,
            name,
            origArgs, // BC-7: pre-RTK args
            outStr,
            false, // not error
            recentToolNames
          );
          // Accumulate for next tool in this loop iteration
          recentToolNames.push(name);
        }

        onToolEnd?.(name, outStr, false);
        return { type: "text" as const, text: outStr };
      } catch (err) {
        const errMsg = err instanceof Error ? err.message : String(err);

        // ADD: write rich observation (BC-1: error branch, Fatal Flaw #4 fix)
        if (sessionId && recentToolNames) {
          writeRichObservation(
            sessionId,
            name,
            origArgs,
            errMsg,
            true, // is error
            recentToolNames
          );
          // Still accumulate failed tool name for precedingTools
          recentToolNames.push(name);
        }

        onToolEnd?.(name, errMsg, true);
        return { type: "text" as const, text: `Error: ${errMsg}`, isError: true };
      }
    })
  );
}
